import Image from "next/image"
import Link from "next/link"
import styles from "@/styles/sponsors-section.module.css" // Reusing the same styles module

export function SponsorsSection() {
  const sponsors = [
    {
      name: "ISKC Knowledge Bridge",
      logo: "/sponsor1.png?height=200&width=400",
    },
    {
      name: "Raw Nextgen LLC",
      logo: "/sponsor2.png?height=200&width=400",
    },
    {
      name: "Harbaji",
      logo: "/sponsor3.png?height=200&width=400",
    },
    {
      name: "KMT Springs",
      logo: "/sponsor4.png?height=200&width=400",
    },
    {
      name: "IGUS Motion Plastics",
      logo: "/sponsor5.png?height=200&width=400",
    }
  ]

  return (
    <section className={styles.sponsorsSection}>
      <div className={styles.container}>
        <div className={`${styles.sectionTitle} animate-on-scroll`}>
          <h2>Our Sponsors</h2>
          <p>The partners who make our journey possible</p>
        </div>

        <div className={styles.sponsorsGrid}>
          {sponsors.map((sponsor, index) => (
            <div
              key={sponsor.name}
              className={`${styles.sponsorCard} animate-on-scroll`}
              style={{ animationDelay: `${index * 0.1}s` }}
            >
              <div className={styles.sponsorLogo}>
                <Image src={sponsor.logo || "/placeholder.svg"} alt={sponsor.name} width={400} height={200} />
              </div>
              <div className={styles.sponsorName}>{sponsor.name}</div>
            </div>
          ))}
        </div>

        <div className={`${styles.sponsorshipInfo} animate-on-scroll`}>
          <div className={styles.infoCard}>
            <h3>Become a Sponsor</h3>
            <p>
              Sponsorship with Centauri Racing is a two-way street. We guarantee high ROI through diverse leverage
              opportunities including logo placement, social media presence, outreach events, and bespoke branding
              opportunities.
            </p>
            <Link href="/contact" className={styles.sponsorBtn}>
              Contact Us
            </Link>
          </div>
        </div>
      </div>
    </section>
  )
}


export function SustainabilityPartnersSection() {
  const sustainabilityPartners = [
    {
      name: "Humane India",
      logo: "/partner1.png?height=200&width=400",
    },
    {
      name: "Eco Echoes",
      logo: "/partner2.png?height=200&width=400",
    },
  ];

  return (
    <section className={styles.sponsorsSection}>
      <div className={styles.container}>
        <div className={`${styles.sectionTitle} animate-on-scroll`}>
          <h2>Sustainability Partners</h2>
          <p>Committed to a Greener Future with</p>
        </div>

        <div className={styles.sustainabilityPartnersGrid}> {/* Changed to sustainabilityPartnersGrid */}
          {sustainabilityPartners.map((partner, index) => (
            <div
              key={partner.name}
              className={`${styles.sponsorCard} animate-on-scroll`}
              style={{ animationDelay: `${index * 0.1}s` }}
            >
              <div className={styles.sponsorLogo} style={{height: '150px'}}>
                <Image src={partner.logo || "/placeholder.svg"} alt={partner.name} width={400} height={200} />
              </div>
              <div className={styles.sponsorName}>{partner.name}</div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}