import styles from "@/styles/blog-page.module.css"
import Link from "next/link";
import Image from "next/image"

const BlogCard = ({ title, date, excerpt, image, link }) => {
    // Modified Link here to use dynamic route
    const dynamicRouteLink = `/blog/${link.split('/').pop()}`; // Create dynamic link from 'link' property

    return (
        <div className={styles.blogCard}>
            <div className={styles.blogImageContainer}>
                <Image
                    src={image || "/placeholder.svg"}
                    alt={title}
                    width={500}
                    height={300}
                    className={styles.blogImage}
                />
                <div className={styles.blogDate}>{date}</div>
            </div>

            <div className={styles.blogContent}>
                <h3>{title}</h3>
                <p>{excerpt}</p>
                <Link href={dynamicRouteLink} className={styles.readMoreBtn}> {/* Use dynamicRouteLink */}
                    Read More
                </Link>
            </div>
        </div>
    );
};

export default BlogCard;