import Image from "next/image"
import Link from "next/link"
import styles from "@/styles/team-section.module.css"

export default function TeamSection() {
  const teamMembers = [
    {
      name: "Soham Udar",
      role: "Team Manager",
      image: "/SohamUdar.png?height=400&width=400",
      description:
        "Oversees our team's direction, coordinating efforts and ensuring we stay aligned with our project's vision.",
    },
    {
      name: "Rishan Gaikwad",
      role: "Software Specialist",
      image: "/RishanGaikwad.png?height=400&width=400",
      description:
        "Expertise in software tools enables us to optimize design simulations and streamline digital aspects of our project.",
    },
    {
      name: "Shvet Muchandi",
      role: "Design Engineer & Analyst",
      image: "/ShvetM.png?height=400&width=400",
      description:
        "Focus on engineering excellence drives the design and functionality of our car, ensuring it meets performance standards.",
    },
    {
      name: "Vibhav Alapati",
      role: "Graphic Design & Social Media Manager",
      image: "/VibhavA.jpg?height=400&width=400",
      description:
        "Creativity and technical skills in design and social media are key to building Centauri Racing's brand presence.",
    },
    {
      name: "Shreeprasad Taklikar",
      role: "Sponsorship & Finance Manager",
      image: "/ShreeprasadT.jpg?height=400&width=400",
      description:
        "Spearheads our sponsorship efforts, building valuable relationships with partners and managing resources.",
    },
  ]

  return (
    <section className={styles.teamSection}>
      <div className={styles.container}>
        <div className={`${styles.sectionTitle} animate-on-scroll`}>
          <h2>Meet Our Team</h2>
          <p>The brilliant minds behind Centauri Racing</p>
        </div>

        <div className={styles.teamGrid}>
          {teamMembers.map((member, index) => (
            <div
              key={member.name}
              className={`${styles.teamCard} animate-on-scroll`}
              style={{ animationDelay: `${index * 0.1}s` }}
            >
              <div className={styles.memberImageContainer}>
                <Image
                  src={member.image || "/placeholder.svg"}
                  alt={member.name}
                  width={400}
                  height={400}
                  className={styles.memberImage}
                />
                <div className={styles.imageBorder}></div>
              </div>

              <div className={styles.memberInfo}>
                <h3>{member.name}</h3>
                <div className={styles.role}>{member.role}</div>
                <p>{member.description}</p>
              </div>

              <div className={styles.cardOverlay}></div>
            </div>
          ))}
        </div>

        <div className={`${styles.teamCta} animate-on-scroll`}>
          <Link href="/team" className={styles.teamBtn}>
            View Full Team Details
          </Link>
        </div>
      </div>
    </section>
  )
}

