"use client"

import { useRef } from "react"
import { motion, useScroll, useTransform } from "framer-motion"
import styles from "@/styles/parallax-effect.module.css"

export default function ParallaxEffect({ children }) {
  const ref = useRef(null)
  const { scrollYProgress } = useScroll({
    target: ref,
    offset: ["start end", "end start"],
  })

  const y = useTransform(scrollYProgress, [0, 1], [0, -100])
  const opacity = useTransform(scrollYProgress, [0, 0.5, 1], [0.6, 1, 0.6])

  return (
    <div ref={ref} className={styles.parallaxContainer}>
      <motion.div className={styles.parallaxContent} style={{ y, opacity }}>
        {children}
      </motion.div>
    </div>
  )
}

